SELECT

FROM products
WHERE source = #{source}
  AND affiliate_url = #{affiliateUrl}
LIMIT 1

SELECT

FROM products
WHERE source = #{source}
  AND external_product_id = #{externalProductId}
LIMIT 1

SELECT

FROM products
WHERE visible_yn = 'Y'
  AND product_id != #{productId}
  AND category_name = #{categoryName}
ORDER BY rating DESC, review_count DESC, product_id DESC
LIMIT #{limit}
